import{_ as a,c as i,o as l,a1 as r}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"Продвинутый уровень: Конвейер и внутренние механизмы | Руководство AI App Factory","description":"Глубокое понимание 7-этапного конвейера AI App Factory, планировщика Sisyphus, механизмов безопасности и разрешений, стратегий обработки ошибок. Освоение оптимизации контекста и продвинутых методов конфигурации.","frontmatter":{"title":"Продвинутый уровень: Конвейер и внутренние механизмы | Руководство AI App Factory","sidebarTitle":"Продвинутый: Конвейер","subtitle":"Продвинутый уровень: Конвейер и внутренние механизмы","description":"Глубокое понимание 7-этапного конвейера AI App Factory, планировщика Sisyphus, механизмов безопасности и разрешений, стратегий обработки ошибок. Освоение оптимизации контекста и продвинутых методов конфигурации.","tags":["Конвейер","Планировщик","Безопасность и разрешения","Обработка ошибок"],"prerequisite":["start-pipeline-overview"],"order":80},"headers":[],"relativePath":"ru/hyz1992/agent-app-factory/advanced/index.md","filePath":"ru/hyz1992/agent-app-factory/advanced/index.md"}'),e={name:"ru/hyz1992/agent-app-factory/advanced/index.md"};function o(s,t,n,p,d,h){return l(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="продвинутыи-уровень-конвеиер-и-внутренние-механизмы" tabindex="-1">Продвинутый уровень: Конвейер и внутренние механизмы <a class="header-anchor" href="#продвинутыи-уровень-конвеиер-и-внутренние-механизмы" aria-label="Permalink to &quot;Продвинутый уровень: Конвейер и внутренние механизмы&quot;">​</a></h1><p>В этой главе подробно рассматриваются основные механизмы и продвинутые функции AI App Factory, включая детальные принципы работы 7-этапного конвейера, стратегии планирования планировщика Sisyphus, механизмы разрешений и безопасности, стратегии обработки ошибок, а также способы экономии затрат на токены через оптимизацию контекста.</p><div class="warning custom-block"><p class="custom-block-title">Предварительные условия</p><p>Перед изучением этой главы убедитесь, что вы завершили:</p><ul><li><a href="./../../start/getting-started/">Быстрый старт</a> и <a href="./../../start/installation/">Установка и настройка</a></li><li><a href="./../../start/pipeline-overview/">Обзор 7-этапного конвейера</a></li><li>Настройку <a href="./../../platforms/claude-code/">Интеграции с платформами</a></li></ul></div><h2 id="содержание-главы" tabindex="-1">Содержание главы <a class="header-anchor" href="#содержание-главы" aria-label="Permalink to &quot;Содержание главы&quot;">​</a></h2><p>Эта глава включает следующие темы:</p><h3 id="детальное-описание-7-этапного-конвеиера" tabindex="-1">Детальное описание 7-этапного конвейера <a class="header-anchor" href="#детальное-описание-7-этапного-конвеиера" aria-label="Permalink to &quot;Детальное описание 7-этапного конвейера&quot;">​</a></h3><ul><li><p><strong><a href="./stage-bootstrap/">Этап 1: Bootstrap — структурирование идеи продукта</a></strong></p><ul><li>Научитесь преобразовывать размытые идеи продукта в структурированные документы</li><li>Поймите формат входных и выходных данных Bootstrap Agent</li></ul></li><li><p><strong><a href="./stage-prd/">Этап 2: PRD — создание документа требований к продукту</a></strong></p><ul><li>Создание PRD уровня MVP, включающего пользовательские истории, список функций и нецели</li><li>Освоение техник декомпозиции требований и расстановки приоритетов</li></ul></li><li><p><strong><a href="./stage-ui/">Этап 3: UI — проектирование интерфейса и прототипов</a></strong></p><ul><li>Использование навыка ui-ux-pro-max для проектирования структуры UI и интерактивных прототипов</li><li>Понимание процесса проектирования интерфейса и лучших практик</li></ul></li><li><p><strong><a href="./stage-tech/">Этап 4: Tech — проектирование технической архитектуры</a></strong></p><ul><li>Проектирование минимально жизнеспособной технической архитектуры и модели данных Prisma</li><li>Освоение принципов выбора технологий и проектирования архитектуры</li></ul></li><li><p><strong><a href="./stage-code/">Этап 5: Code — генерация работающего кода</a></strong></p><ul><li>Генерация фронтенд и бэкенд кода, тестов и конфигураций на основе UI Schema и Tech-дизайна</li><li>Понимание процесса генерации кода и системы шаблонов</li></ul></li><li><p><strong><a href="./stage-validation/">Этап 6: Validation — проверка качества кода</a></strong></p><ul><li>Проверка установки зависимостей, проверка типов, схемы Prisma и качества кода</li><li>Освоение процесса автоматизированной проверки качества</li></ul></li><li><p><strong><a href="./stage-preview/">Этап 7: Preview — создание руководства по развёртыванию</a></strong></p><ul><li>Генерация полной документации по запуску и конфигурации развёртывания</li><li>Изучение интеграции CI/CD и настройки Git Hooks</li></ul></li></ul><h3 id="внутренние-механизмы" tabindex="-1">Внутренние механизмы <a class="header-anchor" href="#внутренние-механизмы" aria-label="Permalink to &quot;Внутренние механизмы&quot;">​</a></h3><ul><li><p><strong><a href="./orchestrator/">Подробное описание планировщика Sisyphus</a></strong></p><ul><li>Понимание того, как планировщик координирует конвейер, управляет состоянием и выполняет проверку разрешений</li><li>Освоение стратегий планирования и принципов конечного автомата</li></ul></li><li><p><strong><a href="./context-optimization/">Оптимизация контекста: выполнение в отдельных сессиях</a></strong></p><ul><li>Научитесь использовать команду <code>factory continue</code> для экономии токенов</li><li>Освоение лучших практик создания новых сессий на каждом этапе</li></ul></li><li><p><strong><a href="./security-permissions/">Механизмы разрешений и безопасности</a></strong></p><ul><li>Понимание матрицы границ возможностей, обработки нарушений прав и механизмов проверки безопасности</li><li>Освоение настройки безопасности и управления разрешениями</li></ul></li><li><p><strong><a href="./failure-handling/">Обработка ошибок и откат изменений</a></strong></p><ul><li>Изучение идентификации ошибок, механизмов повторных попыток, стратегий отката и процессов вмешательства человека</li><li>Освоение техник диагностики и восстановления после сбоев</li></ul></li></ul><h2 id="рекомендации-по-пути-обучения" tabindex="-1">Рекомендации по пути обучения <a class="header-anchor" href="#рекомендации-по-пути-обучения" aria-label="Permalink to &quot;Рекомендации по пути обучения&quot;">​</a></h2><h3 id="рекомендуемыи-порядок-изучения" tabindex="-1">Рекомендуемый порядок изучения <a class="header-anchor" href="#рекомендуемыи-порядок-изучения" aria-label="Permalink to &quot;Рекомендуемый порядок изучения&quot;">​</a></h3><ol><li><p><strong>Сначала изучите 7-этапный конвейер</strong> (по порядку)</p><ul><li>Bootstrap → PRD → UI → Tech → Code → Validation → Preview</li><li>Каждый этап имеет чётко определённые входы и выходы, последовательное изучение позволит построить полное понимание</li></ul></li><li><p><strong>Затем изучите планировщик и оптимизацию контекста</strong></p><ul><li>Поймите, как Sisyphus координирует эти 7 этапов</li><li>Научитесь оптимизировать контекст для экономии затрат на токены</li></ul></li><li><p><strong>Наконец, изучите безопасность и обработку ошибок</strong></p><ul><li>Освойте границы разрешений и механизмы безопасности</li><li>Узнайте о сценариях ошибок и стратегиях реагирования</li></ul></li></ol><h3 id="приоритеты-обучения-для-разных-ролеи" tabindex="-1">Приоритеты обучения для разных ролей <a class="header-anchor" href="#приоритеты-обучения-для-разных-ролеи" aria-label="Permalink to &quot;Приоритеты обучения для разных ролей&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Роль</th><th>Приоритетные разделы</th></tr></thead><tbody><tr><td><strong>Разработчик</strong></td><td>Code, Validation, Tech, Orchestrator</td></tr><tr><td><strong>Менеджер продукта</strong></td><td>Bootstrap, PRD, UI, Preview</td></tr><tr><td><strong>Технический руководитель</strong></td><td>Tech, Code, Security, Failure Handling</td></tr><tr><td><strong>Инженер DevOps</strong></td><td>Validation, Preview, Context Optimization</td></tr></tbody></table><h2 id="следующие-шаги" tabindex="-1">Следующие шаги <a class="header-anchor" href="#следующие-шаги" aria-label="Permalink to &quot;Следующие шаги&quot;">​</a></h2><p>После завершения этой главы вы можете продолжить изучение:</p><ul><li><strong><a href="./../../faq/troubleshooting/">Часто задаваемые вопросы и устранение неполадок</a></strong> — решение проблем при реальном использовании</li><li><strong><a href="./../../faq/best-practices/">Лучшие практики</a></strong> — освоение техник эффективного использования Factory</li><li><strong><a href="./../../appendix/cli-commands/">Справочник команд CLI</a></strong> — полный список команд</li><li><strong><a href="./../../appendix/code-standards/">Стандарты кода</a></strong> — стандарты, которым должен соответствовать сгенерированный код</li></ul><hr><p>💡 <strong>Подсказка</strong>: Если вы столкнулись с проблемами при использовании, сначала обратитесь к разделу <a href="./../../faq/troubleshooting/">Часто задаваемые вопросы и устранение неполадок</a>.</p>',19)])])}const g=a(e,[["render",o]]);export{c as __pageData,g as default};
